import { InstructionReturn } from '@staratlas/data-source';
import { GalacticMarketplaceIDLProgram } from '../constants';

export const NOOP_IX_DATA = Buffer.from([
  0x09, 0xb2, 0x0d, 0x73, 0x81, 0x23, 0xed, 0x66,
]);

/**
 * Runs the no-op instruction
 * This ix does nothing, but can cheaply be added to a transaction to increase compute limit
 * if there isn't space for a compute budget IX.
 * @param program - GalacticMarketplace Program
 * @returns InstructionReturn
 */
export function noop(
  program: GalacticMarketplaceIDLProgram,
): InstructionReturn {
  return async () => ({
    instruction: await program.methods.noop().instruction(),
    signers: [],
  });
}
